    std::uint8_t *aEarthLaneD = pWorkSpace->mEarthLaneD;
    std::uint8_t *aScrapLaneA = pWorkSpace->mScrapLaneA;
    std::uint8_t *aScrapLaneB = pWorkSpace->mScrapLaneB;
    std::uint64_t aCross = 0; std::uint64_t aScatter = 0;

    std::uint64_t aOrbiterA = 0; std::uint64_t aOrbiterB = 0; std::uint64_t aOrbiterC = 0; std::uint64_t aOrbiterD = 0;
    std::uint64_t aOrbiterE = 0; std::uint64_t aOrbiterF = 0; std::uint64_t aOrbiterG = 0; std::uint64_t aOrbiterH = 0;
    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseA(pNonce * 0xA9DEF36443732765ULL + 0xC894F8DD54911C37ULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseC(pNonce * 0xDD8B4E3201C51DE3ULL + 0xAAE9CDEA54991F23ULL);
    std::uint64_t aNonceWordC = TwistMix64::DiffuseB(pNonce * 0xED3F541D42C8E75DULL + 0x9F34371BBAA125C5ULL);
    std::uint64_t aNonceWordD = TwistMix64::DiffuseC(pNonce * 0xBF2B03018A046B35ULL + 0xDC130874D8372AA8ULL);
    std::uint64_t aNonceWordE = TwistMix64::DiffuseB(pNonce * 0xD8E12261CE04AAF3ULL + 0xD77945FDF00ECD82ULL);
    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xE52263DE690E4727ULL + 0xFE97B56E352BA43BULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseA(pNonce * 0xCE522A4E18B9C839ULL + 0x9DD332F778987805ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xA7EA08DDB3A9156BULL + 0xBBCA91D50ED92A1AULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xE3CAE3EECA9CA9CDULL + 0x823B5832FE0A2F7DULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseB(pNonce * 0x96A7162E9F2FCFD7ULL + 0xDEEDE2BAF922FC76ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseA(pNonce * 0xD10A8269B750E1E9ULL + 0xCD76F19C8A2198E2ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseB(pNonce * 0x9E428E0E76270FDFULL + 0xB1E5AD1D4F8D878EULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseA(pNonce * 0xCAAF12DFC2BBE0A5ULL + 0xB7B1C2D629859D0AULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xB7B96E41C756A1F1ULL + 0xEEB2DF890FC3AF23ULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseA(pNonce * 0xCEEFBFB826850E21ULL + 0xC2117AC19E9EF95CULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseB(pNonce * 0xADB3BA26AB73B065ULL + 0xFBE6779829BAAB11ULL);
