            aCross = RotL64(pSnow[((S_BLOCK1 - aIndex + 4088U)) & S_BLOCK1], 10U) ^ RotL64(aSource[((S_BLOCK1 - aIndex + 2325U)) & S_BLOCK1], 21U);
