            //
            aOrbiterE = (aWandererD + RotL64(aIngress, 23U)) + 15193474059544033101U;
            aOrbiterJ = ((aWandererK + RotL64(aPrevious, 44U)) + 2205407222321808102U) + aNonceWordJ;
