            aOrbiterC = ((aWandererB + RotL64(aScatter, 60U)) + 3759673903559111590U) + aOrbiterAssignSaltB[(((31U - aIndex) + 14U)) & S_SALT1];
            aOrbiterF = (aWandererH + RotL64(aCross, 5U)) + 17504774638982771991U;
            aOrbiterD = ((aWandererI + RotL64(aPrevious, 35U)) + 6337266794346067894U) + aOrbiterAssignSaltA[((aIndex + 29U)) & S_SALT1];
