            aOrbiterH = (aOrbiterH + aOrbiterA) + 2374890230402261145U;
            aOrbiterC = (aOrbiterC ^ aOrbiterH) ^ 3306039548578248061U;
            aOrbiterC = RotL64((aOrbiterC * 9683386460365485149U), 5U);
            //
            aOrbiterF = ((aOrbiterF + aOrbiterD) + 1115773693728397900U) + aOrbiterUpdateSaltF[(((31U - aIndex) + 26U)) & S_SALT1];
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 6838317571853969640U;
            aOrbiterH = RotL64((aOrbiterH * 4371856970625120871U), 47U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterH) + 13075612553213582707U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 19U)) & S_SALT1];
            aOrbiterG = ((aOrbiterG ^ aOrbiterJ) ^ 4737087193579867963U) ^ aNonceWordH;
            aOrbiterG = RotL64((aOrbiterG * 13270027885140347811U), 57U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 16828476278022819749U;
            aOrbiterE = (aOrbiterE ^ aOrbiterI) ^ 1163116678116511361U;
            aOrbiterE = RotL64((aOrbiterE * 3063746214308536107U), 37U);
            //
            aOrbiterB = (aOrbiterB + aOrbiterF) + 3128945383638807187U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterB) ^ 16261594633411332201U;
            aOrbiterJ = RotL64((aOrbiterJ * 7341469583888699045U), 23U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterK) + 1381129432720295069U;
            aOrbiterI = (aOrbiterI ^ aOrbiterA) ^ 9893784825356346180U;
            aOrbiterI = RotL64((aOrbiterI * 4444848109600550343U), 19U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterG) + 7474557537008897341U;
            aOrbiterB = ((aOrbiterB ^ aOrbiterK) ^ 12920221315068333332U) ^ aOrbiterUpdateSaltB[(((31U - aIndex) + 21U)) & S_SALT1];
            aOrbiterB = RotL64((aOrbiterB * 12553361047106649801U), 43U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterI) + 838729147164632902U) + aOrbiterUpdateSaltE[((aIndex + 4U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterC) ^ 5131267126051066219U;
            aOrbiterD = RotL64((aOrbiterD * 8859621015816625035U), 29U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 3519688587148448109U;
            aOrbiterF = (aOrbiterF ^ aOrbiterG) ^ 8274390573261991810U;
            aOrbiterF = RotL64((aOrbiterF * 9363113441175551111U), 11U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterE) + 9277161506423335431U;
            aOrbiterA = (aOrbiterA ^ aOrbiterD) ^ 4731329734958756083U;
            aOrbiterA = RotL64((aOrbiterA * 3621686070747480633U), 53U);
            //
            aIngress = aOrbiterA ^ RotL64(aOrbiterB, 38U);
            aIngress = aIngress + (RotL64(aOrbiterH, 11U) ^ aOrbiterK);
            aIngress = aIngress + (RotL64(aOrbiterF, 3U) ^ aOrbiterE);
            aIngress = aIngress + (aOrbiterJ ^ RotL64(aOrbiterG, 19U));
            aIngress = aIngress + (RotL64(aOrbiterC, 47U) ^ aOrbiterI);
            aIngress = aIngress + RotL64(aOrbiterD, 23U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererC = aWandererC + ((((RotL64(aIngress, 5U) + aOrbiterG) + RotL64(aOrbiterF, 34U)) + RotL64(aCarry, 5U)) + aWandererUpdateSaltC[(((31U - aIndex) + 7U)) & S_SALT1]);
            aWandererG = aWandererG ^ (((RotL64(aCross, 53U) + aOrbiterF) + RotL64(aOrbiterH, 3U)) + aNonceWordD);
            aWandererF = aWandererF + ((RotL64(aScatter, 11U) + RotL64(aOrbiterI, 39U)) + aOrbiterE);
            aWandererK = aWandererK ^ (((RotL64(aPrevious, 43U) + RotL64(aOrbiterA, 51U)) + aOrbiterK) + aNonceWordP);
